  ('dietitian-moex-08647', 'dietitian', 'dietitian-moex-098-cd594556', 'sub-dietitian-03', NULL, 'single_choice', 'γ－次亞麻油酸（γ-linolenic acid）在人體內可由下列何種代謝生成？', '["α-linolenic acid", "pyruvic acid", "linoleic acid", "Acetyl CoA"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "e6d9fb027d26", "answer_pdf_sha1": "c7bc2a7b664f", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08648', 'dietitian', 'dietitian-moex-098-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列何種胺基酸之代謝異常和心血管疾病之發生有關？', '["Arginine", "Methionine", "Phenylalanine", "Glutamine"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "e6d9fb027d26", "answer_pdf_sha1": "c7bc2a7b664f", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08649', 'dietitian', 'dietitian-moex-098-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關半必需胺基酸（semiessential amino acids）之敘述，何者正確？', '["對重症病患而言，穀胺酸因需求高而成為必需胺基酸", "若甲硫胺酸攝取不足時，半胱胺酸則是必需胺基酸", "當酪胺酸攝取不足時，苯丙胺酸便成為必需胺基酸", "嬰兒肝臟的尿素循環代謝效率差，以致使組胺酸成為必需胺基酸"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "e6d9fb027d26", "answer_pdf_sha1": "c7bc2a7b664f", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08650', 'dietitian', 'dietitian-moex-098-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列何種胺基酸在正常人為非必需胺基酸，但在苯酮尿症（Phenylketonuria, PKU）患者則為必需胺基酸，須 從食物中獲取？', '["methionine", "phenylalanine", "tyrosine", "lysine"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "e6d9fb027d26", "answer_pdf_sha1": "c7bc2a7b664f", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08651', 'dietitian', 'dietitian-moex-098-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列敘述何者錯誤？', '["自然界中的醣類以果糖甜度最高", "Aspartame為一種人工甘味劑", "澱粉可以被口腔中的α-amylase水解消化為maltose", "肌肉中的glycogen可以代謝為glucose以維持血糖濃度的恆定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "e6d9fb027d26", "answer_pdf_sha1": "c7bc2a7b664f", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08652', 'dietitian', 'dietitian-moex-098-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關醣類的敘述，何者錯誤？', '["果糖在肝臟可轉變成葡萄糖再送至各組織細胞進行醣解作用", "過剩的葡萄糖可轉變為脂肪，儲藏在脂肪組織中", "飲食葡萄糖在胰島素促進下進入肝臟可轉變為肝醣儲存", "人體在血糖不足時，可進行肝醣分解，以維持正常的血糖值"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "e6d9fb027d26", "answer_pdf_sha1": "c7bc2a7b664f", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
